  function cycleSignupAvatar(direction) {
    var overlay = document.querySelector(".kg-auth-overlay");
    authAvatarIndex = (authAvatarIndex + direction + AUTH_AVATARS.length) % AUTH_AVATARS.length;
    var avatar = AUTH_AVATARS[authAvatarIndex];
    if (!overlay || !avatar) return;

    var title = overlay.querySelector("[data-avatar-title]");
    var image = overlay.querySelector(".kg-avatar-character");
    var overlayImage = overlay.querySelector(".kg-avatar-light");
    var nameInput = overlay.querySelector("[name='avatarName']");
    var imageInput = overlay.querySelector("[name='avatarImage']");
    var profileImageInput = overlay.querySelector("[name='avatarProfileImage']");
    if (title) title.textContent = avatar.name;
    if (image) {
      image.setAttribute("src", avatar.image);
      image.setAttribute("alt", avatar.name);
    }
    if (overlayImage) overlayImage.setAttribute("src", avatar.overlay);
    if (nameInput) nameInput.value = avatar.name;
    if (imageInput) imageInput.value = avatar.image;
    if (profileImageInput) profileImageInput.value = avatar.profileImage;
  }

