  function escapeHtml(value) {
    return String(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  function numberWithSpaces(value) {
    return String(Number(value || 0)).replace(/\B(?=(\d{3})+(?!\d))/g, " ");
  }

  function numberWithCommas(value) {
    return String(Number(value || 0)).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  }

