  function handleClicks() {
    document.addEventListener("click", function (event) {
      var loginButton = event.target.closest("#login-button, .login-button");
      var signupButton = event.target.closest("#signup-button, .signup-button");
      var accountMenuButton = event.target.closest("[data-account-menu]");
      var accountProfileButton = event.target.closest("[data-account-profile]");
      var accountLogoutButton = event.target.closest("[data-account-logout]");
      var profilePostButton = event.target.closest("[data-profile-post]");
      var profile = getProfile();

      if (accountMenuButton) {
        event.preventDefault();
        var nav = accountMenuButton.closest("#meta-nav");
        if (nav) nav.classList.toggle("is-open");
        return;
      }

      if (accountProfileButton) {
        event.preventDefault();
        goToProfile();
        return;
      }

      if (accountLogoutButton) {
        event.preventDefault();
        event.stopPropagation();
        clearProfile();
        updateAuthUI();
        renderProfilePage();
        renderGamePage();
        showToast("notofun");
        return;
      }

      if (!event.target.closest("#meta-nav")) {
        var openMenu = document.querySelector("#meta-nav.kg-account-nav.is-open");
        if (openMenu) openMenu.classList.remove("is-open");
      }

      if (profilePostButton) {
        event.preventDefault();
        var postText = document.querySelector("[data-profile-post-text]");
        if (postText) postText.value = "";
        showToast("Posted to your local profile.");
        return;
      }

      if (loginButton) {
        event.preventDefault();
        if (profile) {
          goToProfile();
        } else {
          openAuth("login");
        }
        return;
      }

      if (signupButton) {
        event.preventDefault();
        event.stopPropagation();
        if (profile) {
          clearProfile();
          updateAuthUI();
          renderProfilePage();
          renderGamePage();
          showToast("notofun");
        } else {
          openAuth("signup");
        }
        return;
      }

      var profileLogin = event.target.closest("[data-profile-login]");
      if (profileLogin) {
        event.preventDefault();
        openAuth("login");
        return;
      }

      var profileSignup = event.target.closest("[data-profile-signup]");
      if (profileSignup) {
        event.preventDefault();
        openAuth("signup");
        return;
      }

      var dotsBtn = event.target.closest("[data-dots-menu]");
      if (dotsBtn) {
        event.preventDefault();
        event.stopPropagation();
        var menuId = dotsBtn.getAttribute("data-dots-menu");
        var dropdown = document.getElementById("dots-" + menuId);
        if (dropdown) {
          var wasOpen = dropdown.classList.contains("is-open");
          document.querySelectorAll(".kg-dots-dropdown.is-open").forEach(function(d) { d.classList.remove("is-open"); });
          if (!wasOpen) dropdown.classList.add("is-open");
        }
        return;
      }

      var editWallBtn = event.target.closest("[data-edit-wall]");
      if (editWallBtn) {
        event.preventDefault();
        event.stopPropagation();
        var editId = editWallBtn.getAttribute("data-edit-wall");
        if (editId) startEditWallPost(editId);
        return;
      }

      var deleteWallBtn = event.target.closest("[data-delete-wall]");
      if (deleteWallBtn) {
        event.preventDefault();
        event.stopPropagation();
        var wallId = deleteWallBtn.getAttribute("data-delete-wall");
        if (wallId) deleteWallPost(wallId);
        return;
      }

      var deleteNewsBtn = event.target.closest("[data-delete-news]");
      if (deleteNewsBtn) {
        event.preventDefault();
        event.stopPropagation();
        var newsId = deleteNewsBtn.getAttribute("data-delete-news");
        if (newsId) deleteNewsItem(newsId);
        return;
      }

      var cancelEditWall = event.target.closest("[data-cancel-edit-wall]");
      if (cancelEditWall) {
        event.preventDefault();
        event.stopPropagation();
        renderWallPosts();
        return;
      }

      var editCommentBtn = event.target.closest("[data-edit-comment]");
      if (editCommentBtn) {
        event.preventDefault();
        event.stopPropagation();
        var editCmtId = editCommentBtn.getAttribute("data-edit-comment");
        if (editCmtId) startEditComment(editCmtId);
        return;
      }

      var cancelCommentBtn = event.target.closest("[data-cancel-comment]");
      if (cancelCommentBtn) {
        event.preventDefault();
        event.stopPropagation();
        renderGameComments(gameIdFromPath());
        renderNewsComments();
        renderWallPosts();
        return;
      }

      if (!event.target.closest(".kg-dots-menu")) {
        document.querySelectorAll(".kg-dots-dropdown.is-open").forEach(function(d) { d.classList.remove("is-open"); });
      }

      var target = event.target.closest("a, button");
      if (!target) return;

      var text = cleanText(target.textContent).toLowerCase();
      if (
        text === "play" ||
        text === "play now" ||
        text === "buy" ||
        text === "get" ||
        target.classList.contains("play-button")
      ) {
        if (target.closest(".content-game") || target.closest(".content-shop")) {
          event.preventDefault();
          showToast("This is a local archive demo. Account, shop, and game actions are saved locally only.");
        }
      }
    }, true);
  }

  var FRIENDS_LIST_KEY = "KaGaMa.offline.friends-list";

  function getFriendsListData() {
    try {
      return JSON.parse(localStorage.getItem(FRIENDS_LIST_KEY) || "{}");
    } catch (e) { return {}; }
  }

  function saveFriendsListData(data) {
    localStorage.setItem(FRIENDS_LIST_KEY, JSON.stringify(data));
  }

  function getMyFriends() {
    var id = getCurrentProfileId();
    if (!id) return [];
    var data = getFriendsListData();
    return data[id] || [];
  }

  function addFriend(targetId) {
    var id = getCurrentProfileId();
    if (!id || id === targetId) return;
    var data = getFriendsListData();
    if (!data[id]) data[id] = [];
    if (data[id].indexOf(targetId) === -1) data[id].push(targetId);
    saveFriendsListData(data);
  }

  function removeFriend(targetId) {
    var id = getCurrentProfileId();
    if (!id) return;
    var data = getFriendsListData();
    if (data[id]) {
      data[id] = data[id].filter(function(f) { return f !== targetId; });
      saveFriendsListData(data);
    }
  }

  function areMutualFriends(id1, id2) {
    var data = getFriendsListData();
    var list1 = data[id1] || [];
    var list2 = data[id2] || [];
    return list1.indexOf(id2) !== -1 && list2.indexOf(id1) !== -1;
  }

  function isFriend(targetId) {
    return getMyFriends().indexOf(targetId) !== -1;
  }

  function viewingProfileId() {
    var parts = window.location.pathname.split("/").filter(Boolean);
    for (var i = 0; i < parts.length; i++) {
      if (parts[i] === "profile" && parts[i + 1]) return parts[i + 1];
    }
    return "";
  }

