  function handleMarketplaceDetail() {
    if (typeof PRODUCT_DATA === "undefined") return;
    var likeBtn = document.querySelector("[data-like-id]");
    if (likeBtn) {
      var likeKey = PRODUCT_LIKE_KEY_PREFIX + PRODUCT_DATA.id;
      var liked = localStorage.getItem(likeKey) === "1";
      if (liked) {
        likeBtn.classList.remove("like-inactive");
        likeBtn.classList.add("like-active");
      }
      likeBtn.addEventListener("click", function(e) {
        e.preventDefault();
        var profile = getProfile();
        if (!profile) { openAuth("signup"); return; }
        var currentlyLiked = localStorage.getItem(likeKey) === "1";
        var likeNum = document.querySelector("[data-like-num='" + PRODUCT_DATA.id + "']");
        var count = likeNum ? parseInt(likeNum.textContent) || 0 : 0;
        if (currentlyLiked) {
          localStorage.removeItem(likeKey);
          likeBtn.classList.remove("like-active");
          likeBtn.classList.add("like-inactive");
          if (likeNum) likeNum.textContent = Math.max(0, count - 1);
        } else {
          localStorage.setItem(likeKey, "1");
          likeBtn.classList.remove("like-inactive");
          likeBtn.classList.add("like-active");
          if (likeNum) likeNum.textContent = count + 1;
        }
      });
    }
    var purchaseBtn = document.querySelector(".purchase-button");
    if (purchaseBtn) {
      purchaseBtn.addEventListener("click", function(e) {
        e.preventDefault();
        var profile = getProfile();
        if (!profile) { openAuth("signup"); return; }
        var price = Number(PRODUCT_DATA.price) || 0;
        var purchaseKey = PRODUCT_PURCHASE_KEY_PREFIX + PRODUCT_DATA.id;
        if (localStorage.getItem(purchaseKey) === "1") {
          alert("You already own this item!");
          return;
        }
        if (profile.gold < price) {
          alert("Not enough gold! You need " + price + " gold.");
          return;
        }
        if (!confirm("Buy " + PRODUCT_DATA.name + " for " + price + " Gold?")) return;
        profile.gold -= price;
        setProfile(profile);
        localStorage.setItem(purchaseKey, "1");
        var goldEl = document.querySelector(".kg-account-gold");
        if (goldEl) goldEl.textContent = profile.gold.toLocaleString();
        var soldNum = document.querySelector("[data-sold-num='" + PRODUCT_DATA.id + "']");
        if (soldNum) soldNum.textContent = (parseInt(soldNum.textContent) || 0) + 1;
        purchaseBtn.textContent = "Owned";
        purchaseBtn.classList.add("owned");
        purchaseBtn.disabled = true;
      });
      var purchaseKey2 = PRODUCT_PURCHASE_KEY_PREFIX + PRODUCT_DATA.id;
      if (localStorage.getItem(purchaseKey2) === "1") {
        purchaseBtn.textContent = "Owned";
        purchaseBtn.classList.add("owned");
        purchaseBtn.disabled = true;
      }
    }
  }

  function handleForms() {
    document.addEventListener("submit", function (event) {
      var gameForm = event.target.closest("[data-game-comment-form]");
      if (gameForm) {
        event.preventDefault();
        submitGameComment(gameForm);
        return;
      }
      var newsForm = event.target.closest("[data-news-comment-form]");
      if (newsForm) {
        event.preventDefault();
        submitNewsComment(newsForm);
        return;
      }
      var wallForm = event.target.closest("[data-wall-post-form]");
      if (wallForm) {
        event.preventDefault();
        submitWallPost(wallForm);
        return;
      }
      var productForm = event.target.closest("[data-product-comment-form]");
      if (productForm) {
        event.preventDefault();
        submitProductComment(productForm);
        return;
      }
      var editWallForm = event.target.closest("[data-edit-wall-form]");
      if (editWallForm) {
        event.preventDefault();
        var postId = editWallForm.getAttribute("data-post-id");
        var ta = editWallForm.querySelector("textarea");
        if (postId && ta && ta.value.trim()) {
          saveEditWallPost(postId, ta.value.trim());
        }
        return;
      }
      var editCommentForm = event.target.closest(".kg-edit-comment-form");
      if (editCommentForm) {
        event.preventDefault();
        var commentId = editCommentForm.getAttribute("data-comment-id");
        var cmtTa = editCommentForm.querySelector("textarea");
        if (commentId && cmtTa && cmtTa.value.trim()) {
          saveEditComment(commentId, cmtTa.value.trim());
        }
        return;
      }
    }, true);
  }

