  function replaceNavIcons() {
    var nav = document.querySelector("nav.menu");
    if (!nav) return;
    var icons = nav.querySelectorAll("i[class^='icon-']");
    for (var i = 0; i < icons.length; i++) {
      var el = icons[i];
      var cls = el.className.trim();
      if (NAV_SVG_MAP[cls]) {
        var span = el.parentNode;
        var tmp = document.createElement("span");
        tmp.innerHTML = NAV_SVG_MAP[cls];
        var svg = tmp.firstChild;
        svg.style.verticalAlign = "middle";
        svg.style.marginRight = "4px";
        span.replaceChild(svg, el);
      }
    }
  }

