  function populateNewsUpload() {
    var isAdmin = getCurrentProfileId() === "1";
    if (!isAdmin) return;
    var newsPage = document.querySelector("#news-list");
    if (!newsPage) return;
    var existing = newsPage.querySelector(".kg-news-upload-form");
    if (existing) return;
    var form = document.createElement("div");
    form.className = "kg-news-upload-form";
    form.innerHTML = [
      '<h3>Post News (Admin)</h3>',
      '<input type="text" class="kg-news-title" placeholder="News title" maxlength="200">',
      '<input type="text" class="kg-news-image" placeholder="Image URL (optional)" maxlength="500">',
      '<textarea class="kg-news-body" placeholder="Write your news article here..." maxlength="5000"></textarea>',
      '<button type="button">Publish</button>'
    ].join("");
    form.querySelector("button").addEventListener("click", async function() {
      var title = form.querySelector(".kg-news-title").value.trim();
      var imageUrl = form.querySelector(".kg-news-image").value.trim();
      var body = form.querySelector(".kg-news-body").value.trim();
      if (!title || !body) { alert("Enter a title and content."); return; }
      if (!imageUrl) imageUrl = ROOT + "/static/img/game-screenshot-600x240.jpg";
      var profile = getProfile();
      await postNewsArticle({
        title: title,
        imageUrl: imageUrl,
        body: body,
        author: profile ? profile.username : "KaGaMa",
        authorAvatar: profile ? profile.avatarImage : BLOCK_BOY_PROFILE_IMAGE
      });
      await renderNewsList();
      form.querySelector(".kg-news-title").value = "";
      form.querySelector(".kg-news-image").value = "";
      form.querySelector(".kg-news-body").value = "";
    });
    newsPage.parentNode.insertBefore(form, newsPage);
  }

  async function renderNewsList() {
    var newsPage = document.querySelector("#news-list");
    if (!newsPage) return;
    var isAdmin = getCurrentProfileId() === "1";
    var items = await fetchNewsItems();
    var list = newsPage.querySelector(".news-list");
    if (!list) {
      list = document.createElement("ul");
      list.className = "news-list news-list-";
      var emptyState = newsPage.querySelector(".kg-empty-news");
      if (emptyState) emptyState.remove();
      newsPage.appendChild(list);
    }
    list.innerHTML = items.map(function(item) {
      var date = new Date(item.createdAt);
      var monthNames = ["January","February","March","April","May","June","July","August","September","October","November","December"];
      var dateStr = monthNames[date.getMonth()] + " " + date.getDate();
      var deleteBtn = isAdmin ? '<button class="kg-news-delete-btn" data-delete-news="' + escapeHtml(item.id) + '">&times;</button>' : '';
      return '<li class="news-item" data-news-id="' + escapeHtml(item.id) + '">' +
        '<a href="' + ROOT + '/news/?article=' + escapeHtml(item.id) + '" data-news-link="' + escapeHtml(item.id) + '">' +
        '<div class="item-image-container"><div class="item-image" style="background-image: url(' + escapeHtml(item.imageUrl) + ');"></div></div>' +
        '<div class="item-text"><h2 class="item-title">' + escapeHtml(item.title) + '</h2>' +
        '<div class="item-excerpt">' + dateStr + '</div></div></a>' + deleteBtn + '</li>';
    }).join("");
    if (items.length === 0 && !newsPage.querySelector(".kg-empty-news")) {
      var empty = document.createElement("div");
      empty.className = "kg-empty-news";
      empty.style.cssText = "text-align:center;padding:60px 20px;color:#8796a2;";
      empty.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="#4e6987"><path d="M20 2H4c-1.1 0-1.99.9-1.99 2L2 22l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2zm-2 12H6v-2h12v2zm0-3H6V9h12v2zm0-3H6V6h12v2z"/></svg><h2 style="color:#fff;font-size:18px;margin:16px 0 8px;">No News Articles Yet</h2><p style="font-size:13px;line-height:1.5;">Check back soon for the latest KaGaMa news and updates!</p>';
      newsPage.appendChild(empty);
    }
  }

  async function deleteNewsItem(newsId) {
    await deleteNewsArticle(newsId);
    await renderNewsList();
  }

  async function renderNewsArticle() {
    var params = new URLSearchParams(window.location.search);
    var articleId = params.get("article");
    if (!articleId) return;
    var item = await fetchNewsArticle(articleId);
    if (!item) return;
    document.title = item.title + " - KaGaMa";
    var date = new Date(item.createdAt);
    var dateStr = date.toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" });
    var mobileContent = document.querySelector("#mobile-page-content");
    if (!mobileContent) return;
    mobileContent.innerHTML = [
      '<article id="news-post" class="content-content news-post-">',
      '<div class="post-image-container">',
      '<div class="post-image" style="background-image: url(' + escapeHtml(item.imageUrl) + ');"></div>',
      '</div>',
      '<div class="post-content">',
      '<div class="avatar-wrapper">',
      '<div class="avatar">',
      '<a href="' + ROOT + '/profile/1/">',
      '<div class="sub-avatar">',
      '<svg class="sub-avatar-image-svg" viewBox="0 0 32 32" height="32px" width="32px">',
      '<defs>',
      '<clipPath id="clip-hexagon"><polygon points="16 0, 30 8, 30 24, 16 32, 2 24, 2 8"></polygon></clipPath>',
      '<linearGradient id="sub-avatar-gradiant" x1="0" x2="0" y1="0" y2="1">',
      '<stop offset="0%" stop-color="#68b3f5"></stop>',
      '<stop offset="100%" stop-color="#a5cffb"></stop>',
      '</linearGradient>',
      '</defs>',
      '<rect width="32" height="32"></rect>',
      '<image class="sub-avatar-image" href="' + escapeHtml(item.authorAvatar || BLOCK_BOY_PROFILE_IMAGE) + '" width="32" height="32"></image>',
      '</svg>',
      '</div>',
      '</a>',
      '</div>',
      '</div>',
      '<div class="body-wrapper">',
      '<div class="post-body">',
      '<div class="arrow-left-border"></div>',
      '<div class="arrow-left"></div>',
      '<h2>' + escapeHtml(item.title) + '</h2>',
      escapeHtml(item.body).replace(/\n/g, '<br>'),
      '</div>',
      '</div>',
      '</div>',
      '<div class="post-created">' + dateStr + '</div>',
      '<div class="post-comments" id="news-comments"></div>',
      '</article>'
    ].join("");
    renderNewsComments();
  }

  async function populateActivity() {
    var el = document.getElementById("activity");
    if (!el) return;
    var items = [];

    // Fetch users from server (real-time, shared across all visitors)
    var serverUsers = [];
    try {
      var r = await fetch(ROOT + "/api/users");
      if (r.ok) serverUsers = await r.json();
    } catch(e) {}

    // If server users available, use them; otherwise fallback to localStorage
    if (serverUsers.length > 0) {
      serverUsers.forEach(function(u) {
        if (u && u.username) {
          items.push({ user: u.username, text: "joined PlayKaGaMa!", img: u.avatarImage || BLOCK_BOY_PROFILE_IMAGE });
        }
      });
    } else {
      var profiles = getProfiles();
      Object.keys(profiles).forEach(function(id) {
        var p = profiles[id];
        if (p && p.username) {
          items.push({ user: p.username, text: "joined PlayKaGaMa!", img: p.avatarImage || BLOCK_BOY_PROFILE_IMAGE });
        }
      });
    }

    var news = await fetchNewsItems();
    news.slice(0, 5).forEach(function(n) {
      if (n.author) {
        items.push({ user: n.author, text: "published a news article!", img: n.imageUrl || ROOT + "/static/img/kogama-logo.webp" });
      }
    });
    if (items.length === 0) {
      items.push({ user: "KaGaMa", text: "Welcome to KaGaMa!", img: ROOT + "/static/img/kogama-logo.webp" });
    }
    el.innerHTML = items.slice(0, 10).map(function(a) {
      return '<a href="#">' +
        '<img src="' + escapeHtml(a.img) + '">' +
        '<span class="time">recently</span>' +
        '<span class="text">' + escapeHtml(a.user) + " " + escapeHtml(a.text) + '</span></a>';
    }).join("");
    setInterval(function() {
      var child = el.firstChild;
      if (child) { el.removeChild(child); el.appendChild(child); }
    }, 4000);
  }

